{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/CommentWrappingRuleSingleLineBlockTest.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class CommentWrappingRuleSingleLineBlockTest {
    private val commentWrappingRuleAssertThat = assertThatRule { CommentWrappingRule() }

    @Test
    fun `Given a single line block containing only a block comment then do not reformat`() {
        val code =
            """
            val foo = { /* no-op */ }
            """.trimIndent()
        commentWrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a single line lambda containing only a block comment then do not reformat`() {
        val code =
            """
            fun foo() {
                val bar = { /* no-op */ }
                val baz = { /* comment */ }
            }
            """.trimIndent()
        commentWrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a single line block with a block comment between braces without spaces then do not reformat`() {
        val code =
            """
            val foo = {/* no-op */}
            """.trimIndent()
        commentWrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given multiple single line blocks with block comments then do not reformat`() {
        val code =
            """
            val foo = { /* no-op */ }
            val bar = { /* another comment */ }
            val baz = { /* yet another */ }
            """.trimIndent()
        commentWrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a single line block with multiline block comment then do not reformat`() {
        val code =
            """
            val foo = { /* comment
                         * with multiple lines
                         */ }
            """.trimIndent()
        // This should still raise an error since the block comment contains newlines
        // but is inside a lambda that spans multiple lines
        commentWrappingRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

